+fn load_from_file(path: &Path, profile: &RuntimeProfile) -> Result<RaptorQConfig, ConfigError> {
+    let contents = std::fs::read_to_string(path)?;
+    let base = profile.to_config();
+    parse_config(&contents, base)
+}
